import React, { Component } from "react";

class Counter extends Component {

    constructor(props) {
        super(props);

        this.state = {
            count: 0
        };
    }

    increment = () => {
        this.setState({
            count: this.state.count + 1
        });
    };

    decrement = () => {
        this.setState({
            count: this.state.count - 1
        });
    };

    sayHello = () => {
        alert("Hello! Member");
    };

    incrementAndHello = () => {
        this.increment();
        this.sayHello();
    };

    sayWelcome = (message) => {
        alert(message);
    };

    handleClick = (event) => {
        alert("I was clicked");
        console.log(event);
    };

    render() {

        return (

            <div>

                <h2>Counter : {this.state.count}</h2>

                <button onClick={this.incrementAndHello}>
                    Increment
                </button>

                <button
                    onClick={this.decrement}
                    style={{ marginLeft: "10px" }}
                >
                    Decrement
                </button>

                <br /><br />

                <button
                    onClick={() => this.sayWelcome("Welcome")}
                >
                    Say Welcome
                </button>

                <br /><br />

                <button onClick={this.handleClick}>
                    Click on Me
                </button>

            </div>

        );
    }
}

export default Counter;
